import './TransactionForm.css';
import { useState } from "react";

const categories = {
  Income: [
    "Salary",
    "Freelancing",
    "Investments",
    "Other"
  ],
  Expense: [
    "Food",
    "Transportation",
    "Shopping",
    "Entertainment",
    "Bills",
    "Healthcare",
    "Education",
    "Other"
  ]
};

function TransactionForm({transactions, setTransactions, balanceAmount, showForm, setShowForm}) {
  const [type, setType] = useState("Expense");
  const [category, setCategory] = useState("");
  const [amount, setAmount] = useState("");
  const [date, setDate] = useState("");
  const [description, setDescription] = useState("");
  const [error, setError] = useState("");

  function handleSubmit() {
    if (!category){
      setError("Please choose category");
      return;
    }
    if (!amount){
      setError("Please enter amount");
      return;
    }
    if (!date){
      setError("Please enter date");
      return;
    }
    if (!description){
      setError("Please enter description");
      return;
    }
    if (type==='Expense' && amount>balanceAmount){
      setError("Insufficient Balance!");
      return;
    }
    setError("");
    const newTransaction = {
      id: Date.now(),
      type,
      category,
      amount,
      date,
      description
    }
    setShowForm(false);
    setTransactions([...transactions,newTransaction]);
    setType("Expense");
    setCategory("");
    setAmount("");
    setDate("");
    setDescription("");
  }
  return (
    <>
    <div className="flex-container">
      <div className="transactionForm-container">
  <h2 className="form-title">Add Transaction</h2>

  <div className="form-row">
    <div className="form-group">
      <label>Type</label>
      <select
        value={type}
        onChange={(e) => {
          setType(e.target.value);
          setCategory("");
        }}
      >
        <option value="Expense">Expense</option>
        <option value="Income">Income</option>
      </select>
    </div>

    <div className="form-group">
      <label>Category</label>
      <select
        value={category}
        onChange={(e) => setCategory(e.target.value)}
      >
        <option value="" disabled>
          Choose Category
        </option>

        {categories[type].map((item) => (
          <option key={item} value={item}>
            {item}
          </option>
        ))}
      </select>
    </div>
  </div>

  <div className="form-row">
    <div className="form-group">
      <label>Amount</label>
      <input
        type="number"
        value={amount}
        onChange={(e) => setAmount(e.target.value)}
      />
    </div>

    <div className="form-group">
      <label>Date</label>
      <input
        type="date"
        value={date}
        onChange={(e) => setDate(e.target.value)}
      />
    </div>
  </div>

  <div className="form-group description-group">
    <label>Description</label>
    <textarea
      value={description}
      placeholder="Add Description"
      onChange={(e) => setDescription(e.target.value)}
    />
  </div>

  {error && <p className="error-message">{error}</p>}

  <div className="button-row">
    <button onClick={handleSubmit}>
      Save
    </button>
  </div>
</div>
    </div>
    </>
  );
}

export default TransactionForm;
